// Object literal with shorthand method
const name = 'Alice';
const age = 30;
const user = { name, age, greet() { return `Hi, ${this.name}`; } };

// Property access
console.log(user.name);      // 'Alice'
console.log(user['age']);    // 30

// Iteration
console.log(Object.keys(user));    // ['name', 'age', 'greet']
console.log(Object.values(user));  // ['Alice', 30, [Function]]
console.log(Object.entries(user)); // [['name','Alice'], ...]

// Shallow copy with spread
const updated = { ...user, age: 31 };

// Optional chaining — safe deep access
const city = user?.address?.city; // undefined (no error)
